  3→const FREEDOM_WALL_ITEM_TYPES = ["doodle", "sticker", "stamp", "note"];
  4→const DEFAULT_ITEMS_LIMIT = 200;
  5→const MAX_ITEMS_LIMIT = 400;
  6→const NOTE_FONT_STYLES = ["normal", "bold", "italic"];
  7→const NOTE_FONT_FAMILIES = [
  8→    "Georgia",
  9→    "Courier New",
 10→    "Trebuchet MS",
 11→    "Arial",
 12→    "Times New Roman"
 13→];
 14→
 15→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
 16→
 17→const parseLimit = (limit) => {
 18→    const parsedLimit = Number(limit ?? DEFAULT_ITEMS_LIMIT);
 19→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > MAX_ITEMS_LIMIT){
 20→        throw {status: 400, error: `limit should be an integer between 1 and ${MAX_ITEMS_LIMIT}`};
 21→    }
 22→    return Math.floor(parsedLimit);
 23→};
 24→
 25→const parseTypeFilters = (types) => {
 26→    if(!types){
 27→        return [];
 28→    }
 29→
 30→    const parsedTypes = String(types)
 31→        .split(",")
 32→        .map((value) => value.trim().toLowerCase())
 33→        .filter(Boolean);
 34→
 35→    const uniqueTypes = [...new Set(parsedTypes)].filter((type) => FREEDOM_WALL_ITEM_TYPES.includes(type));
 36→    return uniqueTypes;
 37→};
 38→
 39→const parseColor = (value, fallback) => {
 40→    if(typeof value !== "string"){
 41→        return fallback;
 42→    }
 43→
 44→    const trimmed = value.trim();
 45→    if(!trimmed){
 46→        return fallback;
 47→    }
 48→
 49→    return trimmed;
 50→};
 51→
 52→const normalizeNumber = (value, fallback) => {
 53→    const parsedValue = Number(value);
 54→    if(Number.isNaN(parsedValue)){
 55→        return fallback;
 56→    }
 57→    return parsedValue;
 58→};
 59→
 60→const normalizePosition = (value, fallback) => clamp(normalizeNumber(value, fallback), 0, 1);
 61→
 62→const sanitizeDoodlePayload = (payload) => {
 63→    const points = Array.isArray(payload?.points)
 64→        ? payload.points
 65→            .map((point) => Number(point))
 66→            .filter((point) => !Number.isNaN(point))
 67→            .map((point) => clamp(point, 0, 1))
 68→        : [];
 69→
 70→    if(points.length < 4){
 71→        throw {status: 400, error: "doodle payload points must contain at least 2 coordinate pairs"};
 72→    }
 73→
 74→    const sanitizedPoints = points.length % 2 === 0
 75→        ? points
 76→        : points.slice(0, -1);
 77→
 78→    const normalizedSize = clamp(normalizeNumber(payload?.size, 2.8), 1, 24);
 79→    return {
 80→        points: sanitizedPoints,
 81→        color: parseColor(payload?.color, "#5f92ff"),
 82→        size: normalizedSize,
 83→        // Backward compatibility for older DB check constraints that still expect strokeWidth.
 84→        strokeWidth: normalizedSize
 85→    };
 86→};
 87→
 88→const sanitizeStickerPayload = (payload) => {
 89→    const stickerId = typeof payload?.stickerId === "string" ? payload.stickerId.trim() : "";
 90→    if(!stickerId){
 91→        throw {status: 400, error: "sticker payload requires stickerId"};
 92→    }
 93→
 94→    return {
 95→        stickerId: stickerId,
 96→        x: normalizePosition(payload?.x, 0.5),
 97→        y: normalizePosition(payload?.y, 0.5),
 98→        scale: clamp(normalizeNumber(payload?.scale, 1), 0.25, 6),
 99→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360)
100→    };
101→};
102→
103→const sanitizeStampPayload = (payload) => {
104→    const stamp = typeof payload?.stamp === "string" ? payload.stamp.trim() : "";
105→    if(!stamp){
106→        throw {status: 400, error: "stamp payload requires stamp"};
107→    }
108→
109→    return {
110→        stamp: stamp,
111→        x: normalizePosition(payload?.x, 0.5),
112→        y: normalizePosition(payload?.y, 0.5),
113→        scale: clamp(normalizeNumber(payload?.scale, 1), 0.35, 5),
114→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360)
115→    };
116→};
117→
118→const sanitizeNotePayload = (payload) => {
119→    const text = typeof payload?.text === "string" ? payload.text.trim() : "";
120→    if(!text){
121→        throw {status: 400, error: "note payload requires text"};
122→    }
123→
124→    const requestedFontFamily = typeof payload?.fontFamily === "string" ? payload.fontFamily.trim() : "";
125→    const requestedFontStyle = typeof payload?.fontStyle === "string" ? payload.fontStyle.trim().toLowerCase() : "";
126→
127→    return {
128→        text: text.slice(0, 800),
129→        x: normalizePosition(payload?.x, 0.45),
130→        y: normalizePosition(payload?.y, 0.45),
131→        width: clamp(normalizeNumber(payload?.width, 0.26), 0.12, 0.9),
132→        height: clamp(normalizeNumber(payload?.height, 0.2), 0.1, 0.8),
133→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360),
134→        fontFamily: NOTE_FONT_FAMILIES.includes(requestedFontFamily) ? requestedFontFamily : "Arial",
135→        fontStyle: NOTE_FONT_STYLES.includes(requestedFontStyle) ? requestedFontStyle : "normal",
136→        fontColor: parseColor(payload?.fontColor, "#1f2937"),
137→        bgColor: parseColor(payload?.bgColor, "#fff4a8"),
138→        fontSize: clamp(normalizeNumber(payload?.fontSize, 16), 10, 64)
139→    };
140→};
141→
142→const sanitizePayloadByType = (itemType, payload) => {
143→    if(!payload || typeof payload !== "object" || Array.isArray(payload)){
144→        throw {status: 400, error: "payload should be an object"};
145→    }
146→
147→    if(itemType === "doodle"){
148→        return sanitizeDoodlePayload(payload);
149→    }
150→    if(itemType === "sticker"){
151→        return sanitizeStickerPayload(payload);
152→    }
153→    if(itemType === "stamp"){
154→        return sanitizeStampPayload(payload);
155→    }
156→    if(itemType === "note"){
157→        return sanitizeNotePayload(payload);
158→    }
159→
160→    throw {status: 400, error: "invalid freedom wall item type"};
161→};
162→
163→const throwMappedDatabaseError = (error, fallbackErrorMessage) => {
164→    const code = String(error?.code || "");
165→    const message = error?.message || fallbackErrorMessage;
166→    const details = error?.details || "";
167→
168→    if(code === "23514"){
169→        throw {
170→            status: 400,
171→            error: `database check constraint rejected payload: ${message}${details ? ` (${details})` : ""}`
172→        };
173→    }
174→
175→    if(code === "22P02"){
176→        throw {status: 400, error: "invalid uuid or malformed value in request"};
177→    }
178→
179→    throw {status: 500, error: fallbackErrorMessage};
180→};
