182→const assertActiveWeek = async(weekId) => {
183→    const {data: week, error: weekError} = await supabase
184→        .from("freedom_wall_weeks")
185→        .select("id, week_start, week_end, status")
186→        .eq("id", weekId)
187→        .maybeSingle();
188→
189→    if(weekError){
190→        console.error("supabase error while reading freedom wall week:", weekError.message);
191→        throw {status: 500, error: "failed to read freedom wall week"};
192→    }
193→
194→    if(!week?.id){
195→        throw {status: 404, error: "freedom wall week not found"};
196→    }
197→
198→    const nowIso = new Date().toISOString();
199→    if(week.status !== "active" || nowIso < week.week_start || nowIso >= week.week_end){
200→        throw {status: 409, error: "freedom wall week is not active"};
201→    }
202→
203→    return week;
204→};
