263→export const getFreedomWallItemsService = async(weekId, limit, cursor, types) => {
264→    if(!weekId){
265→        throw {status: 400, error: "weekId is required"};
266→    }
267→
268→    const parsedLimit = parseLimit(limit);
269→    const typeFilters = parseTypeFilters(types);
270→
271→    let query = supabase
272→        .from("freedom_wall_items")
273→        .select(selectItemColumns)
274→        .eq("week_id", weekId)
275→        .is("deleted_at", null)
276→        .order("z_index", {ascending: true})
277→        .order("created_at", {ascending: true})
278→        .order("id", {ascending: true})
279→        .limit(parsedLimit + 1);
280→
281→    if(cursor){
282→        query = query.gt("created_at", cursor);
283→    }
284→
285→    if(typeFilters.length > 0){
286→        query = query.in("item_type", typeFilters);
287→    }
288→
289→    const {data: items, error: itemsError} = await query;
290→
291→    if(itemsError){
292→        console.error("supabase error while reading freedom wall items:", itemsError.message);
293→        throw {status: 500, error: "failed to fetch freedom wall items"};
294→    }
295→
296→    const hasMore = (items || []).length > parsedLimit;
297→    const slicedItems = hasMore ? items.slice(0, parsedLimit) : (items || []);
298→    const nextCursor = hasMore
299→        ? slicedItems[slicedItems.length - 1]?.created_at || null
300→        : null;
301→
302→    return {
303→        data: slicedItems,
304→        hasMore: hasMore,
305→        nextCursor: nextCursor
306→    };
307→};
