309→export const createFreedomWallItemService = async({weekId, itemType, payload, zIndex = 0, userId}) => {
310→    if(!userId){
311→        throw {status: 401, error: "not authorized"};
312→    }
313→
314→    if(!weekId){
315→        throw {status: 400, error: "weekId is required"};
316→    }
317→
318→    const normalizedType = typeof itemType === "string" ? itemType.trim().toLowerCase() : "";
319→    if(!FREEDOM_WALL_ITEM_TYPES.includes(normalizedType)){
320→        throw {status: 400, error: "invalid freedom wall item type"};
321→    }
322→
323→    await assertActiveWeek(weekId);
324→
325→    const sanitizedPayload = sanitizePayloadByType(normalizedType, payload);
326→    const parsedZIndex = clamp(normalizeNumber(zIndex, 0), -100000, 100000);
327→
328→    const {data: createdItem, error: createError} = await supabase
329→        .from("freedom_wall_items")
330→        .insert({
331→            week_id: weekId,
332→            user_id: userId,
333→            item_type: normalizedType,
334→            payload: sanitizedPayload,
335→            z_index: parsedZIndex
336→        })
337→        .select(selectItemColumns)
338→        .single();
339→
340→    if(createError){
341→        console.error("supabase error while creating freedom wall item:", createError.message);
342→        throwMappedDatabaseError(createError, "failed to create freedom wall item");
343→    }
344→
345→    return {item: createdItem};
346→};
