348→export const updateFreedomWallItemService = async({itemId, payload, zIndex, userId}) => {
349→    if(!userId){
350→        throw {status: 401, error: "not authorized"};
351→    }
352→
353→    if(!itemId){
354→        throw {status: 400, error: "itemId is required"};
355→    }
356→
357→    if(payload === undefined && zIndex === undefined){
358→        throw {status: 400, error: "payload or zIndex is required"};
359→    }
360→
361→    const {data: existingItem, error: existingItemError} = await supabase
362→        .from("freedom_wall_items")
363→        .select("id, week_id, user_id, item_type, payload, z_index")
364→        .eq("id", itemId)
365→        .is("deleted_at", null)
366→        .maybeSingle();
367→
368→    if(existingItemError){
369→        console.error("supabase error while reading freedom wall item:", existingItemError.message);
370→        throw {status: 500, error: "failed to read freedom wall item"};
371→    }
372→
373→    if(!existingItem?.id){
374→        throw {status: 404, error: "freedom wall item not found"};
375→    }
376→
377→    if(String(existingItem.user_id) !== String(userId)){
378→        throw {status: 403, error: "not allowed to edit this freedom wall item"};
379→    }
380→
381→    await assertActiveWeek(existingItem.week_id);
382→
383→    const updatePayload = {};
384→    if(payload !== undefined){
385→        const mergedPayload = {
386→            ...(existingItem.payload || {}),
387→            ...(payload || {})
388→        };
389→        updatePayload.payload = sanitizePayloadByType(existingItem.item_type, mergedPayload);
390→    }
391→
392→    if(zIndex !== undefined){
393→        updatePayload.z_index = clamp(normalizeNumber(zIndex, existingItem.z_index || 0), -100000, 100000);
394→    }
395→
396→    const {data: updatedItem, error: updateError} = await supabase
397→        .from("freedom_wall_items")
398→        .update(updatePayload)
399→        .eq("id", itemId)
400→        .select(selectItemColumns)
401→        .single();
402→
403→    if(updateError){
404→        console.error("supabase error while updating freedom wall item:", updateError.message);
405→        throwMappedDatabaseError(updateError, "failed to update freedom wall item");
406→    }
407→
408→    return {item: updatedItem};
409→};
