 405→        onMutate: async({payload}) => {
 406→            const optimisticId = `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
 407→            const optimisticItem = {
 408→                id: optimisticId,
 409→                week_id: payload.weekId,
 410→                user_id: currentUserId,
 411→                item_type: payload.itemType,
 412→                payload: payload.payload,
 413→                z_index: payload.zIndex || 0,
 414→                created_at: new Date().toISOString(),
