 451→        onMutate: async({itemId, payload}) => {
 452→            let previousItem = null;
 453→            setItemsCache((items) => {
 454→                previousItem = items.find((item) => String(item?.id) === String(itemId)) || null;
 455→                if(!previousItem){
 456→                    return items;
 457→                }
 458→
 459→                return items.map((item) => {
 460→                    if(String(item?.id) !== String(itemId)){
 461→                        return item;
 462→                    }
 463→
 464→                    const mergedPayload = payload?.payload !== undefined
 465→                        ? {...(item?.payload || {}), ...(payload.payload || {})}
 466→                        : item?.payload;
 467→
 468→                    return {
 469→                        ...item,
 470→                        payload: mergedPayload,
 471→                        z_index: payload?.zIndex !== undefined ? payload.zIndex : item?.z_index
 472→                    };
 473→                });
 474→            });
 475→            return {previousItem: previousItem};
 476→        },
