 3→create or replace function public.rotate_freedom_wall_week()
 4→returns void
 5→language plpgsql
 6→security definer
 7→set search_path = public
 8→as $$
 9→declare
10→    v_week_start timestamptz;
11→    v_week_end timestamptz;
12→begin
13→    perform pg_advisory_xact_lock(hashtext('freedom_wall_week_rotate'));
14→
15→    v_week_start := (date_trunc('week', now() at time zone 'UTC') at time zone 'UTC');
16→    v_week_end := v_week_start + interval '7 days';
17→
18→    update public.freedom_wall_weeks
19→    set status = 'archived'
20→    where status = 'active'
21→      and week_start < v_week_start;
22→
23→    insert into public.freedom_wall_weeks (week_start, week_end, status)
24→    values (v_week_start, v_week_end, 'active')
25→    on conflict (week_start)
26→    do update set
27→        week_end = excluded.week_end,
28→        status = 'active';
29→end;
30→$$;
31→
32→select public.rotate_freedom_wall_week();
33→
34→select cron.schedule(
35→    'freedom-wall-weekly-reset',
36→    '0 0 * * 1',
37→    $$select public.rotate_freedom_wall_week();$$
38→);
