 1→-- Compatibility patch for older freedom wall schemas that had doodle/sticker-only checks.
 2→-- Run this in Supabase SQL editor once.
 3→
 4→do $$
 5→declare
 6→    constraint_row record;
 7→begin
 8→    if to_regclass('public.freedom_wall_items') is null then
 9→        raise notice 'public.freedom_wall_items does not exist; skip patch';
10→        return;
11→    end if;
12→
13→    for constraint_row in
14→        select conname
15→        from pg_constraint
16→        where conrelid = 'public.freedom_wall_items'::regclass
17→          and contype = 'c'
18→    loop
19→        execute format('alter table public.freedom_wall_items drop constraint if exists %I', constraint_row.conname);
20→    end loop;
21→end $$;
22→
23→alter table public.freedom_wall_items
24→    add constraint freedom_wall_items_item_type_check
25→    check (item_type in ('doodle', 'sticker', 'stamp', 'note'));
26→
